 71	
 72	  const currentStepId = activeStep.id as string;
 73	
 74	  const backingStoreNextConditions = React.useCallback(() => {
 75	    if (state.tier1BackingStore.length === 0) return false;
 76	    if (
 77	      state.tier1Policy === PlacementPolicy.Mirror &&
 78	      state.tier1BackingStore.length < 2
 79	    )
 80	      return false;
 81	    if (
 82	      state.tier2Policy === PlacementPolicy.Mirror &&
 83	      state.tier2BackingStore.length < 2
 84	    )
 85	      return false;
 86	    if (!!state.tier2Policy && state.tier2BackingStore.length === 0)
 87	      return false;
 88	    return true;
