 90	    state.tier1BackingStore.length,
 91	    state.tier1Policy,
 92	    state.tier2BackingStore.length,
 93	    state.tier2Policy,
 94	  ]);
 95	
 96	  const namespaceStoreNextConditions = React.useCallback(() => {
 97	    if (state.namespacePolicyType === NamespacePolicyType.SINGLE) {
 98	      return (
 99	        state.readNamespaceStore.length === 1 &&
100	        state.writeNamespaceStore.length === 1
101	      );
102	    }
103	    if (state.namespacePolicyType === NamespacePolicyType.CACHE) {
104	      return (
105	        !!state.hubNamespaceStore &&
106	        !!state.cacheBackingStore &&
107	        validateDuration(state.timeToLive)
108	      );
109	    }
110	    if (state.namespacePolicyType === NamespacePolicyType.MULTI) {
111	      return (
112	        state.readNamespaceStore.length >= 1 &&
113	        state.writeNamespaceStore.length === 1
114	      );
115	    }
116	    return false;
