144	        return state.bucketClassType === BucketClassType.STANDARD
145	          ? !!state.tier1Policy
146	          : !!state.namespacePolicyType;
147	      case CreateStepsBC.RESOURCES:
148	        return state.bucketClassType === BucketClassType.STANDARD
149	          ? backingStoreNextConditions()
150	          : namespaceStoreNextConditions();
151	      case CreateStepsBC.REVIEW:
152	        return creationConditionsSatisfied();
153	      default:
154	        return false;
155	    }
156	  }, [
157	    currentStepId,
158	    state.bucketClassName,
159	    state.bucketClassType,
160	    state.tier1Policy,
161	    state.namespacePolicyType,
162	    backingStoreNextConditions,
163	    namespaceStoreNextConditions,
164	    creationConditionsSatisfied,
165	  ]);
166	
167	  const getPayload = React.useCallback(() => {
168	    const metadata = {
169	      apiVersion: getAPIVersionForModel(NooBaaBucketClassModel),
170	      kind: NooBaaBucketClassModel.kind,
171	      metadata: {
172	        name: state.bucketClassName,
173	        namespace: namespace,
174	      },
175	    };
176	    let payload = null;
177	    if (state.bucketClassType === BucketClassType.STANDARD) {
178	      payload = {
179	        ...metadata,
180	        spec: {
181	          placementPolicy: {
182	            tiers: [
183	              {
184	                placement: state.tier1Policy,
185	                backingStores: state.tier1BackingStore.map(getName),
186	              },
187	            ],
188	          },
189	        },
190	      };
191	      if (state.tier2Policy) {
192	        payload.spec.placementPolicy.tiers.push({
193	          placement: state.tier2Policy,
194	          backingStores: state.tier2BackingStore.map(getName),
195	        });
196	      }
197	    } else {
198	      switch (state.namespacePolicyType) {
199	        case NamespacePolicyType.SINGLE:
200	          payload = {
201	            ...metadata,
202	            spec: {
203	              namespacePolicy: {
204	                type: state.namespacePolicyType,
205	                single: {
206	                  resource: getName(state.readNamespaceStore[0]),
207	                },
208	              },
209	            },
210	          };
211	          break;
212	        case NamespacePolicyType.MULTI:
213	          payload = {
214	            ...metadata,
215	            spec: {
216	              namespacePolicy: {
217	                type: state.namespacePolicyType,
218	                multi: {
219	                  writeResource: getName(state.writeNamespaceStore[0]),
220	                  readResources: state.readNamespaceStore.map(getName),
221	                },
222	              },
223	            },
224	          };
225	          break;
