227	          payload = {
228	            ...metadata,
229	            spec: {
230	              namespacePolicy: {
231	                type: state.namespacePolicyType,
232	                cache: {
233	                  caching: {
234	                    ttl: state.timeToLive,
235	                  },
236	                  hubResource: getName(state.hubNamespaceStore),
237	                },
