333	        </Button>
334	        <Button
335	          variant="secondary"
336	          onClick={goToPrevStep}
337	          isDisabled={currentStepId === CreateStepsBC.GENERAL || isLoading}
338	        >
339	          {t('Back')}
340	        </Button>
341	        <Button
342	          variant="link"
343	          onClick={() => navigate(-1)}
