353	const CreateBucketClass: React.FC = () => {
354	  const { t } = useCustomTranslation();
355	
356	  const { odfNamespace } = useODFNamespaceSelector();
357	
358	  const [state, dispatch] = React.useReducer(reducer, initialState);
359	  const { ns } = useParams();
360	  const namespace = ns || odfNamespace;
361	
362	  const launcher = useModal();
363	
364	  const launchNamespaceStoreModal = React.useCallback(
365	    () => launcher(NamespaceStoreCreateModal, { isOpen: true }),
366	    [launcher]
367	  );
368	  const launchBackingStoreModal = React.useCallback(
369	    () => launcher(CreateBackingStoreFormModal, { isOpen: true }),
370	    [launcher]
371	  );
372	
373	  const renderNamespaceStorePage = () => {
374	    switch (state.namespacePolicyType) {
375	      case NamespacePolicyType.SINGLE:
376	        return (
377	          <SingleNamespaceStorePage
378	            state={state}
379	            dispatch={dispatch}
380	            namespace={namespace}
381	            launchModal={launchNamespaceStoreModal}
382	          />
383	        );
384	      case NamespacePolicyType.CACHE:
385	        return (
386	          <CacheNamespaceStorePage
387	            state={state}
388	            dispatch={dispatch}
389	            namespace={namespace}
390	            launchModal={launchNamespaceStoreModal}
391	            launchBackingStoreModal={launchBackingStoreModal}
392	          />
393	        );
394	      case NamespacePolicyType.MULTI:
395	        return (
396	          <MultiNamespaceStorePage
397	            state={state}
398	            dispatch={dispatch}
399	            namespace={namespace}
400	            launchModal={launchNamespaceStoreModal}
401	          />
402	        );
403	      default:
404	        return null;
405	    }
406	  };
407	
408	  const steps = [
409	    {
410	      id: CreateStepsBC.GENERAL,
411	      name: t('General'),
412	      component: (
413	        <GeneralPage dispatch={dispatch} state={state} namespace={namespace} />
414	      ),
415	    },
416	    {
417	      id: CreateStepsBC.PLACEMENT,
418	      name: t('Placement Policy'),
419	      component:
420	        state.bucketClassType === BucketClassType.STANDARD ? (
421	          <PlacementPolicyPage state={state} dispatch={dispatch} />
422	        ) : (
423	          <NamespacePolicyPage state={state} dispatch={dispatch} />
424	        ),
425	    },
426	    {
427	      id: CreateStepsBC.RESOURCES,
428	      name: t('Resources'),
429	      component:
430	        state.bucketClassType === BucketClassType.STANDARD ? (
431	          <BackingStorePage
432	            state={state}
433	            dispatcher={dispatch}
434	            namespace={namespace}
435	          />
436	        ) : (
437	          renderNamespaceStorePage()
438	        ),
439	    },
440	    {
441	      id: CreateStepsBC.REVIEW,
442	      name: t('Review'),
443	      component: <ReviewPage state={state} />,
444	    },
445	  ];
446	
447	  return (
448	    <>
449	      <div className="odf-create-operand__header">
450	        <Title
451	          size="2xl"
452	          headingLevel="h1"
453	          className="odf-create-operand__header-text"
454	        >
455	          {t('Create new BucketClass')}
456	        </Title>
457	        <p className="help-block">
458	          {t(
459	            'BucketClass is a CRD representing a class for buckets that defines tiering policies and data placements for an OBC.'
460	          )}
461	        </p>
462	      </div>
463	      <div className="nb-create-bc-wizard">
464	        <NamespaceSafetyBox>
465	          <Wizard
466	            isVisitRequired
467	            footer={
468	              <BucketClassWizardFooter
469	                state={state}
470	                dispatch={dispatch}
471	                namespace={namespace}
472	              />
473	            }
474	          >
475	            {steps.map((step) => (
476	              <WizardStep key={step.id} id={step.id} name={step.name}>
477	                {step.component}
478	              </WizardStep>
479	            ))}
480	          </Wizard>
481	        </NamespaceSafetyBox>
482	      </div>
483	    </>
484	  );
485	};
486	
487	export default CreateBucketClass;

